types_and_interfaces.definition:
type UserTextContent = { text: string };
type AgentTextContent = { text: string };
type AgentToolCallContent = { tool_name: string; summary: string; details?: Record<string, unknown> };
type ManualObsPrefilled = { label: string; normalized_key: string; value: string; unit: string | null; period_start: string | null; period_end: string | null; };
type ManualObsRequestContent = { pending_id: string; prefilled: ManualObsPrefilled };
type ReportReadyContent = { report_id: string; title: string; html_snapshot_url: string; pdf_url: string | null };
type ErrorContent = { message: string; retryable: boolean };
type ChatMessageContent = UserTextContent | AgentTextContent | AgentToolCallContent | ManualObsRequestContent | ReportReadyContent | ErrorContent;

type TokenEvent = { event_name: 'token'; payload: { delta: string } };
type ToolCallEvent = { event_name: 'tool_call'; payload: { tool_name: string; summary: string; details?: Record<string, unknown> } };
type ManualObsRequestEvent = { event_name: 'manual_obs_request'; payload: { pending_id: string; prefilled: { label: string; normalized_key: string; value: string; unit: string | null; period_start: string | null; period_end: string | null } } };
type ReportReadyEvent = { event_name: 'report_ready'; payload: { report_id: string; title: string; html_snapshot_url: string; pdf_url: string | null } };
type ErrorEvent = { event_name: 'error'; payload: { message: string; retryable: boolean } };
type DoneEvent = { event_name: 'done'; payload: Record<string, never> };
type ChatSseEvent = TokenEvent | ToolCallEvent | ManualObsRequestEvent | ReportReadyEvent | ErrorEvent | DoneEvent;

type Period = { type: 'FY' | 'Q' | 'YTD' | 'custom'; start_date: string; end_date: string; label?: string };
type ComputeDerivationInput = { observation_ids: string[]; operation: 'sum' | 'average' | 'delta' | 'ratio' | 'count'; expected_periods?: Period[] };
type Coverage = { present_periods: Period[]; expected_periods: Period[]; fraction: number | null };
type ComputeDerivationOutput = { derivation_result_id: string; value: number; unit: string; coverage: Coverage; input_observation_ids: string[]; status: 'fresh' | 'reused'; stale: boolean };

type PendingStatusDb = 'pending' | 'confirmed' | 'skipped' | 'timed_out';
type PendingStatusApi = 'pending' | 'confirmed' | 'skipped' | 'timeout';
type PendingObservationResponse = { pending_id: string; status: PendingStatusApi; observation_id: string | null; created_at: string; expires_at: string };

type ReportListItem = { report_id: string; version: number; status: 'draft' | 'final'; language: string; generated_at: string; client_id: string | null; source_report_id: string | null };
type ReportDetail = ReportListItem & { html_snapshot_url: string; pdf_url: string | null };
type ReportVersionsResponse = { versions: Array<{ report_id: string; version: number; source_report_id: string | null; generated_at: string; status: 'draft' | 'final'; language: string }> };
